import styled from 'styled-components';

export const FormBox = styled.div`
    width: 70%;
    border-right: 3px dotted #252525; 
`;

export const BtnNext = styled.button`
    display: inline-flex;
    font-size: 1.7em;
`;

export const BtnPrev = styled.button`
    display: inline-flex;

`;
